# DSA: Hash Maps and Frequency Counting

# Two Sum (classic interview problem)
def two_sum(nums, target):
    seen = {}
    for i, n in enumerate(nums):
        complement = target - n
        if complement in seen:
            return [seen[complement], i]
        seen[n] = i
    return []

print(f"Two Sum: {two_sum([2,7,11,15], 9)}")  # [0,1]

# Character frequency
def char_freq(s):
    freq = {}
    for c in s:
        freq[c] = freq.get(c, 0) + 1
    return freq

print(f"Freq: {char_freq('hello')}")

# Anagram check
def is_anagram(s1, s2):
    return char_freq(s1) == char_freq(s2)

print(f"Anagram: {is_anagram('listen', 'silent')}")
